import json

# 1. Parse the raw_data_sample_json string into a Python dictionary.
data = json.loads(context['raw_data_sample_json'])

# 2. Examine the structure of the dictionary and extract relevant information.
# The structure seems to be:
# {
#   "context": {...},
#   "error": null,
#   "interaction": {...},
#   "query": {...},
#   "results": [...]
# }

# Let's check for "query" and "results" to analyze search relevance and missing products.
query_details = data.get('query', {})
results = data.get('results', [])
interaction = data.get('interaction', {})

issues = []

# Analyze Missing Products and Search Relevance
# Check if there's a query and if results are present.
if not query_details:
    issues.append("Potential issue: No query details found, making it hard to assess search relevance.")
else:
    search_term = query_details.get('query_text')
    if search_term:
        issues.append(f"Search query: '{search_term}'")
        if not results:
            issues.append(f"Potential issue: No results returned for the query '{search_term}'. This could indicate missing products or a search relevance problem.")
        else:
            issues.append(f"Number of search results: {len(results)}")
            # Check if clicked products are in the results
            clicked_products = [click['product_id'] for click in interaction.get('clicks', [])]
            result_product_ids = [result['product_id'] for result in results]

            if clicked_products:
                for clicked_id in clicked_products:
                    if clicked_id not in result_product_ids:
                        issues.append(f"Potential search relevance issue: Product '{clicked_id}' was clicked but is not present in the returned search results. This suggests an inconsistency or a relevance problem.")
            else:
                issues.append("No click interactions for this query, so cannot directly assess relevance based on clicks vs. results.")

            # Check if any product in results has missing or incorrect data in its fields
            for product in results:
                product_id = product.get('product_id', 'N/A')
                product_name = product.get('product_name')
                price = product.get('price')
                currency = product.get('currency')
                brand = product.get('brand')
                category = product.get('category')
                image_url = product.get('image_url')
                description = product.get('description')

                if not product_name:
                    issues.append(f"Potential data issue for product '{product_id}': Missing product_name.")
                if not price or not isinstance(price, (int, float)):
                    issues.append(f"Potential data issue for product '{product_id}': Missing or incorrect price ({price}).")
                if not currency:
                    issues.append(f"Potential data issue for product '{product_id}': Missing currency.")
                if not brand:
                    issues.append(f"Potential data issue for product '{product_id}': Missing brand.")
                if not category:
                    issues.append(f"Potential data issue for product '{product_id}': Missing category.")
                if not image_url:
                    issues.append(f"Potential data issue for product '{product_id}': Missing image_url.")
                if not description:
                    issues.append(f"Potential data issue for product '{product_id}': Missing description.")

    else:
        issues.append("Potential issue: Query text is missing in the query details.")

# Check error field
if data.get('error'):
    issues.append(f"Critical issue: An error occurred in the system: {data['error']}")

# Summarize findings
if not issues:
    final_report = "No significant issues identified based on the provided raw data sample."
else:
    final_report = "Analysis of the e-commerce raw data sample revealed the following potential issues:\n" + "\n".join([f"- {issue}" for issue in issues])

FINAL(final_report)

